import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"圆明园遗址","description":"","frontmatter":{},"headers":[],"relativePath":"history/yuanmingyuan-ruins.md","filePath":"history/yuanmingyuan-ruins.md","lastUpdated":1784720050000}'),o={name:"history/yuanmingyuan-ruins.md"};function n(i,t,d,s,h,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="圆明园遗址" tabindex="-1">圆明园遗址 <a class="header-anchor" href="#圆明园遗址" aria-label="Permalink to &quot;圆明园遗址&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">📖 完整导览</p><p>本页为<strong>历史遗址视角</strong>。圆明园完整导览（含大水法、海晏堂、西洋楼、福海等 6 个子景点详解与图片）请见 → <a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园</a></p></div><blockquote><p>&quot;断壁残垣诉沧桑，万园之园成焦土。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>圆明园遗址位于北京市海淀区清华西路，是清代皇家园林圆明园的残存遗迹。圆明园始建于清康熙年间，历经康雍乾三朝150余年的营造，成为&quot;万园之园&quot;&quot;东方凡尔赛&quot;。1860年英法联军和1900年八国联军的两次洗劫，使这座人类文明的瑰宝化为废墟。</p><p>如今，圆明园遗址作为全国重点文物保护单位和爱国主义教育基地，向世人诉说着那段屈辱的历史。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">7:00-19:00（旺季），7:00-17:30（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">大门门票10元，西洋楼遗址15元，全景模型展10元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-5小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线圆明园站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市海淀区清华西路28号</td></tr></tbody></table><h2 id="历史背景" tabindex="-1">历史背景 <a class="header-anchor" href="#历史背景" aria-label="Permalink to &quot;历史背景&quot;">​</a></h2><h3 id="辉煌时期" tabindex="-1">辉煌时期 <a class="header-anchor" href="#辉煌时期" aria-label="Permalink to &quot;辉煌时期&quot;">​</a></h3><p>圆明园是清代皇帝的&quot;夏宫&quot;，每年夏季，皇帝都会在此处理政务、休闲娱乐。园中汇集了天下名园胜景，仿建了江南园林、西洋建筑，收藏了无数的奇珍异宝、历代书画。</p><p>法国作家雨果曾这样描述圆明园：</p><blockquote><p>&quot;在世界的某个角落，有一个世界奇迹。这个奇迹叫圆明园。一个几乎是超人的民族的想象力所能产生的成就尽在于此。&quot;</p></blockquote><h3 id="第一次浩劫" tabindex="-1">第一次浩劫 <a class="header-anchor" href="#第一次浩劫" aria-label="Permalink to &quot;第一次浩劫&quot;">​</a></h3><p>1860年10月6日，英法联军攻入圆明园。士兵们疯狂抢掠，将园中珍宝洗劫一空。10月18日，英军统帅额尔金下令纵火焚烧圆明园。大火持续三天三夜，这座&quot;万园之园&quot;化为焦土。</p><h3 id="第二次浩劫" tabindex="-1">第二次浩劫 <a class="header-anchor" href="#第二次浩劫" aria-label="Permalink to &quot;第二次浩劫&quot;">​</a></h3><p>1900年，八国联军再次入侵北京，圆明园残存的建筑再遭洗劫。此后，园中的石材、木材被附近村民和军阀盗拆，用于修建房屋。到1949年新中国成立时，圆明园已成一片荒芜。</p><h2 id="遗址现状" tabindex="-1">遗址现状 <a class="header-anchor" href="#遗址现状" aria-label="Permalink to &quot;遗址现状&quot;">​</a></h2><h3 id="西洋楼遗址" tabindex="-1">西洋楼遗址 <a class="header-anchor" href="#西洋楼遗址" aria-label="Permalink to &quot;西洋楼遗址&quot;">​</a></h3><p>西洋楼是圆明园中唯一的西式建筑群，也是今日遗址中保存相对较好的区域。</p><h4 id="大水法" tabindex="-1">大水法 <a class="header-anchor" href="#大水法" aria-label="Permalink to &quot;大水法&quot;">​</a></h4><p>大水法是西洋楼的主景，是一座欧式喷泉。主楼前有椭圆形喷水池，池中有铜鹿、铜狗等动物雕塑，喷泉开启时，水柱从动物口中喷出。</p><p>如今，只剩下几根大理石柱孤独地矗立，成为圆明园遗址的标志性景观。</p><h4 id="海晏堂" tabindex="-1">海晏堂 <a class="header-anchor" href="#海晏堂" aria-label="Permalink to &quot;海晏堂&quot;">​</a></h4><p>海晏堂是西洋楼中最大的建筑，前有著名的十二生肖兽首喷泉。十二生肖兽首人身铜像，按十二时辰依次喷水，正午时十二生肖同时喷水。</p><p>1860年，十二生肖兽首被劫掠，流散海外。目前已有部分兽首回归祖国。</p><h4 id="观水法" tabindex="-1">观水法 <a class="header-anchor" href="#观水法" aria-label="Permalink to &quot;观水法&quot;">​</a></h4><p>观水法是乾隆观看喷泉的地方，设有石屏风和宝座。石屏风上刻有西洋军旗、甲胄、刀剑等图案。</p><h3 id="圆明园四十景" tabindex="-1">圆明园四十景 <a class="header-anchor" href="#圆明园四十景" aria-label="Permalink to &quot;圆明园四十景&quot;">​</a></h3><p>圆明园原有&quot;四十景&quot;之说，每景都是一处精美的园林。如今，这些景点大多只剩下地名和残存的基址。</p><table tabindex="0"><thead><tr><th style="text-align:left;">景名</th><th style="text-align:left;">原景特色</th></tr></thead><tbody><tr><td style="text-align:left;">正大光明</td><td style="text-align:left;">皇帝理政之所</td></tr><tr><td style="text-align:left;">九洲清晏</td><td style="text-align:left;">帝后寝宫</td></tr><tr><td style="text-align:left;">镂月开云</td><td style="text-align:left;">牡丹台，三代皇帝共赏牡丹</td></tr><tr><td style="text-align:left;">天然图画</td><td style="text-align:left;">仿西湖平湖秋月</td></tr><tr><td style="text-align:left;">碧桐书院</td><td style="text-align:left;">皇帝读书之所</td></tr><tr><td style="text-align:left;">慈云普护</td><td style="text-align:left;">供奉欢喜佛</td></tr><tr><td style="text-align:left;">上下天光</td><td style="text-align:left;">临水楼台</td></tr><tr><td style="text-align:left;">杏花春馆</td><td style="text-align:left;">杏花林中的村舍</td></tr><tr><td style="text-align:left;">坦坦荡荡</td><td style="text-align:left;">仿西湖&quot;玉泉观鱼&quot;</td></tr><tr><td style="text-align:left;">茹古涵今</td><td style="text-align:left;">书房</td></tr></tbody></table><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="十二生肖兽首" tabindex="-1">十二生肖兽首 <a class="header-anchor" href="#十二生肖兽首" aria-label="Permalink to &quot;十二生肖兽首&quot;">​</a></h3><p>海晏堂前的十二生肖兽首，是中西合璧的艺术杰作。兽首由意大利传教士郎世宁设计，法国人蒋友仁监修，中国工匠铸造。</p><p>1860年英法联军劫掠后，兽首流散世界各地。经过多方努力，目前已有牛首、猴首、虎首、猪首、马首、鼠首、兔首回归祖国，收藏于保利艺术博物馆和中国国家博物馆。</p><p>龙首据说在台湾，蛇首、羊首、鸡首、狗首至今下落不明。</p><h3 id="文源阁与《四库全书》" tabindex="-1">文源阁与《四库全书》 <a class="header-anchor" href="#文源阁与《四库全书》" aria-label="Permalink to &quot;文源阁与《四库全书》&quot;">​</a></h3><p>文源阁是圆明园中收藏《四库全书》的地方。《四库全书》是清代乾隆年间编纂的大型丛书，是中国历史上最大的一部丛书。</p><p>文源阁于1860年被焚毁，《四库全书》部分被劫掠，部分被焚毁。目前，《四库全书》仅存三部半（文渊阁本、文津阁本、文溯阁本，及文澜阁补抄本）。</p><h3 id="雨果的控诉" tabindex="-1">雨果的控诉 <a class="header-anchor" href="#雨果的控诉" aria-label="Permalink to &quot;雨果的控诉&quot;">​</a></h3><p>法国作家雨果在得知圆明园被焚毁后，写下了著名的控诉信：</p><blockquote><p>&quot;有一天，两个强盗闯进了圆明园。一个抢劫，一个放火。似乎得胜之后，便可以动手行窃了。他们对圆明园进行了大规模的劫掠，赃物由两个胜利者均分。&quot;</p><p>&quot;我们欧洲人是文明人，中国人在我们眼中是野蛮人。这就是文明对野蛮所干的事情。&quot;</p><p>&quot;在历史面前，这两个强盗一个叫法兰西，一个叫英吉利。&quot;</p></blockquote><h3 id="同治重修与中断" tabindex="-1">同治重修与中断 <a class="header-anchor" href="#同治重修与中断" aria-label="Permalink to &quot;同治重修与中断&quot;">​</a></h3><p>同治年间，慈禧太后曾计划重修圆明园。1873年，重修工程启动，但因经费不足，仅修了不到一年就被迫停工。这次重修，反而使圆明园残存的建筑进一步遭到破坏。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="参观心态" tabindex="-1">参观心态 <a class="header-anchor" href="#参观心态" aria-label="Permalink to &quot;参观心态&quot;">​</a></h3><p>游览圆明园，不是看美景，而是看废墟。请带着历史敬畏心前来，了解那段屈辱的历史，铭记&quot;落后就要挨打&quot;的教训。</p><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约3小时）</strong>：</p><p>南门 → 十二生肖兽首展 → 绮春园 → 三园交界 → 长春园 → 西洋楼遗址（谐奇趣→万花阵→养雀笼→方外观→海晏堂→大水法→观水法→线法山→线法墙） → 东门</p><p><strong>深度路线（约5小时）</strong>：</p><p>南门 → 正觉寺 → 绮春园 → 三园交界 → 圆明园（九州景区→福海景区） → 长春园 → 西洋楼遗址 → 全景模型 → 东门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票建议</strong>：一定要购买含西洋楼遗址的联票，否则看不到大水法等标志性景观</li><li><strong>游览车</strong>：园区很大，可乘电瓶车（10-15元/站）节省体力</li><li><strong>讲解服务</strong>：建议请人工讲解或租用语音导览，了解历史背景</li><li><strong>全景模型</strong>：园内有圆明园全景沙盘模型，可以看到圆明园原貌</li><li><strong>拍照注意</strong>：遗址前拍照请保持庄重，不要做出不适当的姿势</li><li><strong>最佳时间</strong>：春秋两季，尤其是秋天银杏黄时</li></ol><h3 id="教育意义" tabindex="-1">教育意义 <a class="header-anchor" href="#教育意义" aria-label="Permalink to &quot;教育意义&quot;">​</a></h3><p>圆明园遗址是爱国主义教育的重要基地。每年有大量中小学生来此参观，接受爱国主义教育。</p><p>遗址前立有&quot;勿忘国耻，振兴中华&quot;的石碑，提醒后人铭记历史，发愤图强。</p><h2 id="历史反思" tabindex="-1">历史反思 <a class="header-anchor" href="#历史反思" aria-label="Permalink to &quot;历史反思&quot;">​</a></h2><p>圆明园的毁灭，是中华民族永远的伤痛。它不仅是一座园林的毁灭，更是中华文明遭受重创的象征。</p><p>今天，我们站在遗址前，不仅要铭记历史的屈辱，更要思考：</p><ul><li>如何才能避免历史悲剧重演？</li><li>如何才能让中华民族永远屹立于世界民族之林？</li><li>如何才能保护好人类共同的文化遗产？</li></ul><p>正如遗址前的标语所说：</p><blockquote><p>&quot;勿忘国耻，振兴中华！&quot;</p></blockquote><hr><p><strong>📍 地址</strong>：北京市海淀区清华西路28号 <strong>📞 电话</strong>：010-62543673 <strong>🌐 官网</strong>：<a href="http://www.yuanmingyuanpark.com" target="_blank" rel="noreferrer">www.yuanmingyuanpark.com</a></p>',65)])])}const g=a(o,[["render",n]]);export{q as __pageData,g as default};
